"use strict";
(() => {
  // game-src/input.ts
  var KEY = {
    LEFT: 37,
    UP: 38,
    RIGHT: 39,
    DOWN: 40,
    W: 87,
    A: 65,
    S: 83,
    D: 68,
    SPACE: 32
  };
  var PREV_BITS_VAR = "__inputPrevBits";
  function readInput(scene2) {
    const im = scene2.getGame().getInputManager();
    let x = 0;
    let y = 0;
    if (im.isKeyPressed(KEY.LEFT) || im.isKeyPressed(KEY.A)) x -= 1;
    if (im.isKeyPressed(KEY.RIGHT) || im.isKeyPressed(KEY.D)) x += 1;
    if (im.isKeyPressed(KEY.UP) || im.isKeyPressed(KEY.W)) y -= 1;
    if (im.isKeyPressed(KEY.DOWN) || im.isKeyPressed(KEY.S)) y += 1;
    const space = im.isKeyPressed(KEY.SPACE);
    const mouse = im.isMouseButtonPressed(0);
    const fire3 = space || mouse;
    const prevVar = scene2.getVariables().get(PREV_BITS_VAR);
    const prev = prevVar.getAsNumber();
    const wasFire = (prev & (1 /* Fire */ | 2 /* Mouse */)) !== 0;
    const firePressed = fire3 && !wasFire;
    let next = 0;
    if (space) next |= 1 /* Fire */;
    if (mouse) next |= 2 /* Mouse */;
    prevVar.setNumber(next);
    return {
      axes: { x, y },
      fire: fire3,
      firePressed,
      cursor: { x: im.getCursorX(), y: im.getCursorY() }
    };
  }

  // game-src/entities.ts
  var ObjectName = {
    Player: "Player",
    Enemy: "Enemy",
    Bullet: "Bullet",
    Cannon: "Cannon",
    EnemyBall: "EnemyBall",
    Castle: "Castle",
    Sea: "Sea",
    Target: "Target",
    DeadZone: "DeadZone",
    Island: "Island",
    Railing: "Railing"
  };
  function spawn(scene2, name, x, y) {
    const obj = scene2.createObject(name, x, y);
    if (!obj) {
      console.warn(`[entities] createObject('${name}') returned null \u2014 is it defined in the scene?`);
    }
    return obj;
  }
  function all(scene2, name) {
    return scene2.getObjects(name);
  }
  function firstOrNull(scene2, name) {
    const arr = scene2.getObjects(name);
    return arr.length > 0 ? arr[0] : null;
  }

  // game-src/projectiles.ts
  var OFFSCREEN_PAD = 48;
  var BALL_DISPLAY_SIZE_PX = 28;
  function fire(scene2, kind, x, y, dx, dy, speed) {
    const len = Math.hypot(dx, dy) || 1;
    const vx = dx / len * speed;
    const vy = dy / len * speed;
    const p = spawn(scene2, kind, x, y);
    if (!p) return null;
    if (kind === ObjectName.Bullet || kind === ObjectName.EnemyBall) {
      const native = p.getWidth();
      if (native > 0) p.setScale(BALL_DISPLAY_SIZE_PX / native);
    }
    const v = p.getVariables();
    v.get("vx").setNumber(vx);
    v.get("vy").setNumber(vy);
    return p;
  }
  function update(scene2, kind, dt2) {
    const game = scene2.getGame();
    const w = game.getGameResolutionWidth();
    const h = game.getGameResolutionHeight();
    for (const p of all(scene2, kind)) {
      const v = p.getVariables();
      const nx = p.getX() + v.get("vx").getAsNumber() * dt2;
      const ny = p.getY() + v.get("vy").getAsNumber() * dt2;
      if (nx < -OFFSCREEN_PAD || nx > w + OFFSCREEN_PAD || ny < -OFFSCREEN_PAD || ny > h + OFFSCREEN_PAD) {
        p.deleteFromScene(scene2);
        continue;
      }
      p.setX(nx);
      p.setY(ny);
    }
  }

  // game-src/cannon.ts
  var BULLET_SPEED = 720;
  var AIM_CENTER_DEG = -90;
  var AIM_SPREAD_DEG = 15;
  var AIM_SENSITIVITY_PX = 140;
  var BOTTOM_MARGIN = 14;
  var RAILING_BOTTOM_MARGIN = 0;
  var CANNON_Z = 10;
  var RAILING_Z = 5;
  function ensureCannon(scene2) {
    let c = firstOrNull(scene2, ObjectName.Cannon);
    if (c) return c;
    const game = scene2.getGame();
    const w = game.getGameResolutionWidth();
    const h = game.getGameResolutionHeight();
    c = spawn(scene2, ObjectName.Cannon, 0, 0);
    if (c) {
      const cw = c.getWidth();
      const ch = c.getHeight();
      const cx = w / 2 - cw / 2;
      const cy = h - ch - BOTTOM_MARGIN;
      c.setX(cx);
      c.setY(cy);
      c.setZOrder(CANNON_Z);
      console.log(`[cannon] spawned ${cw}\xD7${ch} at ${cx},${cy}`);
    }
    const r = spawn(scene2, ObjectName.Railing, 0, 0);
    if (r) {
      const rw = r.getWidth();
      const rh = r.getHeight();
      const rx = w / 2 - rw / 2;
      const ry = h - rh - RAILING_BOTTOM_MARGIN;
      r.setX(rx);
      r.setY(ry);
      r.setZOrder(RAILING_Z);
      console.log(`[railing] spawned ${rw}\xD7${rh} at ${rx},${ry}`);
    }
    return c;
  }
  function computeAimDeg(cannonX, cursorX) {
    const t = Math.max(-1, Math.min(1, (cursorX - cannonX) / AIM_SENSITIVITY_PX));
    return AIM_CENTER_DEG + t * AIM_SPREAD_DEG;
  }
  function aim(cannon2, cursorX) {
    const aimDeg = computeAimDeg(cannon2.getCenterX(), cursorX);
    cannon2.setAngle(aimDeg + 90);
    return aimDeg;
  }
  function fire2(scene2, cannon2, aimDeg) {
    const rad = aimDeg * Math.PI / 180;
    const dx = Math.cos(rad);
    const dy = Math.sin(rad);
    const muzzleOffset = cannon2.getHeight() * 0.45;
    const muzzleX = cannon2.getCenterX() + dx * muzzleOffset;
    const muzzleY = cannon2.getCenterY() + dy * muzzleOffset;
    fire(scene2, ObjectName.Bullet, muzzleX, muzzleY, dx, dy, BULLET_SPEED);
  }

  // game-src/background.ts
  var SEA_Z = -20;
  var ISLAND_Z = -15;
  var DEADZONE_Z = -5;
  var SKY_HEIGHT_PX = 130;
  var ISLAND_Y = 110;
  var DEADZONE_INSET_PX = 56;
  var INIT_VAR = "__bgInit";
  function deadZoneInset() {
    return DEADZONE_INSET_PX;
  }
  function ensureBackground(scene2) {
    const vars = scene2.getVariables();
    if (vars.get(INIT_VAR).getAsNumber() !== 0) return;
    vars.get(INIT_VAR).setNumber(1);
    const w = scene2.getGame().getGameResolutionWidth();
    const sea = spawn(scene2, ObjectName.Sea, 0, SKY_HEIGHT_PX);
    if (sea) sea.setZOrder(SEA_Z);
    const island = spawn(scene2, ObjectName.Island, 0, 0);
    if (island) {
      const iw = island.getWidth();
      island.setX(w / 2 - iw / 2);
      island.setY(ISLAND_Y);
      island.setZOrder(ISLAND_Z);
    }
    const dzLeft = spawn(scene2, ObjectName.DeadZone, DEADZONE_INSET_PX, 0);
    if (dzLeft) dzLeft.setZOrder(DEADZONE_Z);
    const dzRight = spawn(scene2, ObjectName.DeadZone, w - DEADZONE_INSET_PX, 0);
    if (dzRight) dzRight.setZOrder(DEADZONE_Z);
    console.log(`[background] sky/sea/island/deadzones spawned`);
  }

  // game-src/enemy.ts
  var FIRE_INTERVAL_SEC = 2.2;
  var SPAWN_GAP_SEC = 1;
  var ENTRY_SPEED_PX_PER_SEC = 220;
  var ENEMY_BALL_SPEED = 300;
  var INITIAL_HP = 3;
  var TOTAL_SHIPS_TO_SINK = 3;
  var STOP_INSIDE_PLAYFIELD_PX = 6;
  var TARGET_OFFSET_FRAC_X = 0.55;
  var TARGET_OFFSET_FRAC_Y = 0.3;
  var SUNK_COUNT_VAR = "__shipsSunk";
  var NEXT_SIDE_VAR = "__nextSide";
  var SPAWN_TIMER_VAR = "__spawnTimer";
  var INIT_FLAG_VAR = "__enemyInit";
  var SHIP_ID_COUNTER = "__shipIdCounter";
  function nextShipId(scene2) {
    const counter = scene2.getVariables().get(SHIP_ID_COUNTER);
    const id = counter.getAsNumber() + 1;
    counter.setNumber(id);
    return id;
  }
  function findTargetForShip(scene2, shipId) {
    for (const t of all(scene2, ObjectName.Target)) {
      if (t.getVariables().get("shipId").getAsNumber() === shipId) return t;
    }
    return null;
  }
  function findShipForTarget(scene2, target) {
    const id = target.getVariables().get("shipId").getAsNumber();
    for (const e of all(scene2, ObjectName.Enemy)) {
      if (e.getVariables().get("shipId").getAsNumber() === id) return e;
    }
    return null;
  }
  var ENEMY_Y = 140;
  function spawnShip(scene2, side) {
    const w = scene2.getGame().getGameResolutionWidth();
    const dz = deadZoneInset();
    const y = ENEMY_Y;
    const e = spawn(scene2, ObjectName.Enemy, side === "left" ? -400 : w + 400, y);
    if (!e) return null;
    const ew = e.getWidth();
    const startX = side === "left" ? -ew - 8 : w + 8;
    const playfieldLeft = dz + STOP_INSIDE_PLAYFIELD_PX;
    const playfieldRight = w - dz - STOP_INSIDE_PLAYFIELD_PX - ew;
    const centeredX = (playfieldLeft + playfieldRight) / 2;
    const targetX = side === "left" ? centeredX - 8 : centeredX + 8;
    e.setX(startX);
    e.setY(y);
    const id = nextShipId(scene2);
    const v = e.getVariables();
    v.get("shipId").setNumber(id);
    v.get("hp").setNumber(INITIAL_HP);
    v.get("state").setNumber(0);
    v.get("targetX").setNumber(targetX);
    v.get("fireTimer").setNumber(0);
    const t = spawn(
      scene2,
      ObjectName.Target,
      startX + ew * TARGET_OFFSET_FRAC_X,
      y + e.getHeight() * TARGET_OFFSET_FRAC_Y
    );
    if (t) t.getVariables().get("shipId").setNumber(id);
    console.log(`[enemy] spawn ${side} id=${id} ${ew}\xD7${e.getHeight()} \u2192 target x=${targetX}`);
    return e;
  }
  function damage(scene2, enemy, amount) {
    const hpVar = enemy.getVariables().get("hp");
    const next = hpVar.getAsNumber() - amount;
    hpVar.setNumber(next);
    if (next <= 0) {
      const id = enemy.getVariables().get("shipId").getAsNumber();
      const t = findTargetForShip(scene2, id);
      if (t) t.deleteFromScene(scene2);
      enemy.deleteFromScene(scene2);
      const sunk = scene2.getVariables().get(SUNK_COUNT_VAR);
      sunk.setNumber(sunk.getAsNumber() + 1);
      scene2.getVariables().get(SPAWN_TIMER_VAR).setNumber(0);
      console.log(`[enemy] sunk id=${id} (${sunk.getAsNumber()}/${TOTAL_SHIPS_TO_SINK})`);
      return true;
    }
    console.log(`[enemy] hit hp=${next}`);
    return false;
  }
  function shipsSunk(scene2) {
    return scene2.getVariables().get(SUNK_COUNT_VAR).getAsNumber();
  }
  function isLevelComplete(scene2) {
    return shipsSunk(scene2) >= TOTAL_SHIPS_TO_SINK;
  }
  function tick(scene2, dt2, cannonX, cannonY) {
    const vars = scene2.getVariables();
    if (vars.get(INIT_FLAG_VAR).getAsNumber() === 0) {
      vars.get(INIT_FLAG_VAR).setNumber(1);
      spawnShip(scene2, "left");
      vars.get(NEXT_SIDE_VAR).setNumber(1);
      return;
    }
    const enemies = all(scene2, ObjectName.Enemy);
    if (enemies.length === 0) {
      if (isLevelComplete(scene2)) return;
      const t = vars.get(SPAWN_TIMER_VAR).getAsNumber() + dt2;
      if (t >= SPAWN_GAP_SEC) {
        vars.get(SPAWN_TIMER_VAR).setNumber(0);
        const sideBit = vars.get(NEXT_SIDE_VAR).getAsNumber();
        spawnShip(scene2, sideBit === 0 ? "left" : "right");
        vars.get(NEXT_SIDE_VAR).setNumber(1 - sideBit);
      } else {
        vars.get(SPAWN_TIMER_VAR).setNumber(t);
      }
      return;
    }
    for (const e of enemies) {
      const v = e.getVariables();
      const stateVal = v.get("state").getAsNumber();
      if (stateVal === 0) {
        const target = v.get("targetX").getAsNumber();
        const x = e.getX();
        const dir = target > x ? 1 : -1;
        const nx = x + dir * ENTRY_SPEED_PX_PER_SEC * dt2;
        if (dir === 1 && nx >= target || dir === -1 && nx <= target) {
          e.setX(target);
          v.get("state").setNumber(1);
          v.get("fireTimer").setNumber(0);
          console.log(`[enemy] arrived at ${target} (now firing)`);
        } else {
          e.setX(nx);
        }
      } else {
        const ft = v.get("fireTimer").getAsNumber() + dt2;
        if (ft >= FIRE_INTERVAL_SEC) {
          v.get("fireTimer").setNumber(0);
          const ex = e.getCenterX();
          const ey = e.getCenterY();
          fire(scene2, ObjectName.EnemyBall, ex, ey, cannonX - ex, cannonY - ey, ENEMY_BALL_SPEED);
        } else {
          v.get("fireTimer").setNumber(ft);
        }
      }
      const id = v.get("shipId").getAsNumber();
      const t = findTargetForShip(scene2, id);
      if (t) {
        t.setX(e.getX() + e.getWidth() * TARGET_OFFSET_FRAC_X);
        t.setY(e.getY() + e.getHeight() * TARGET_OFFSET_FRAC_Y);
      }
    }
  }

  // game-src/state.ts
  var INITIAL_PLAYER_HP = 5;
  var HP_VAR = "playerHp";
  var STATE_VAR = "gameState";
  var HP_INIT_FLAG = "__hpInit";
  function ensureInit(scene2) {
    const vars = scene2.getVariables();
    if (vars.get(HP_INIT_FLAG).getAsNumber() === 0) {
      vars.get(HP_INIT_FLAG).setNumber(1);
      vars.get(HP_VAR).setNumber(INITIAL_PLAYER_HP);
      vars.get(STATE_VAR).setNumber(0);
      console.log(`[state] init hp=${INITIAL_PLAYER_HP}`);
    }
  }
  function getState(scene2) {
    const s = scene2.getVariables().get(STATE_VAR).getAsNumber();
    return s === 1 ? "won" : s === 2 ? "lost" : "playing";
  }
  function damagePlayer(scene2, amount) {
    if (getState(scene2) !== "playing") return;
    const hpVar = scene2.getVariables().get(HP_VAR);
    const next = Math.max(0, hpVar.getAsNumber() - amount);
    hpVar.setNumber(next);
    console.log(`[state] player hp=${next}`);
    if (next <= 0) {
      scene2.getVariables().get(STATE_VAR).setNumber(2);
      console.log(`[state] LOST`);
    }
  }
  function markWon(scene2) {
    if (getState(scene2) !== "playing") return;
    scene2.getVariables().get(STATE_VAR).setNumber(1);
    console.log(`[state] WON`);
  }

  // game-src/collisions.ts
  var BULLET_DAMAGE = 1;
  var ENEMY_BALL_DAMAGE = 1;
  function hit(a, b) {
    return gdjs.RuntimeObject.collisionTest(a, b, false);
  }
  function resolveBulletHits(scene2) {
    const bullets = all(scene2, ObjectName.Bullet);
    if (bullets.length === 0) return { kills: 0, parries: 0 };
    const targets = all(scene2, ObjectName.Target);
    const enemyBalls = all(scene2, ObjectName.EnemyBall);
    let kills = 0;
    let parries = 0;
    for (const b of bullets) {
      let consumed = false;
      for (const eb of enemyBalls) {
        if (hit(b, eb)) {
          eb.deleteFromScene(scene2);
          b.deleteFromScene(scene2);
          parries += 1;
          consumed = true;
          break;
        }
      }
      if (consumed) continue;
      for (const t of targets) {
        if (hit(b, t)) {
          b.deleteFromScene(scene2);
          const ship = findShipForTarget(scene2, t);
          const state = ship ? ship.getVariables().get("state").getAsNumber() : 0;
          if (ship && state === 1 && damage(scene2, ship, BULLET_DAMAGE)) {
            kills += 1;
          }
          break;
        }
      }
    }
    return { kills, parries };
  }
  function resolveEnemyBallHits(scene2, cannon2) {
    if (!cannon2) return 0;
    const balls = all(scene2, ObjectName.EnemyBall);
    if (balls.length === 0) return 0;
    let dmg = 0;
    for (const b of balls) {
      if (hit(b, cannon2)) {
        b.deleteFromScene(scene2);
        damagePlayer(scene2, ENEMY_BALL_DAMAGE);
        dmg += ENEMY_BALL_DAMAGE;
      }
    }
    return dmg;
  }

  // game-src/main.ts
  var scene = runtimeScene;
  ensureInit(scene);
  ensureBackground(scene);
  var cannon = ensureCannon(scene);
  var playing = getState(scene) === "playing";
  var dt = scene.getElapsedTime() / 1e3;
  var input = readInput(scene);
  if (cannon && playing) {
    const aimDeg = aim(cannon, input.cursor.x);
    if (input.firePressed) fire2(scene, cannon, aimDeg);
    tick(scene, dt, cannon.getCenterX(), cannon.getCenterY());
  }
  update(scene, ObjectName.Bullet, dt);
  update(scene, ObjectName.EnemyBall, dt);
  if (playing) {
    resolveBulletHits(scene);
    resolveEnemyBallHits(scene, cannon);
    if (isLevelComplete(scene)) markWon(scene);
  }
})();
